          )}

          {/* Fontes de trafego */}
          {data.sources && data.sources.length > 0 && (
            <div className="kpi-card">
              <h3 className="text-sm font-bold mb-4" style={{ color: "var(--text-muted)" }}>FONTES DE TRAFEGO</h3>
