                  <YAxis dataKey="channel" type="category" tick={{ fill: "var(--text-muted)", fontSize: 11 }} width={140} />
                  <Tooltip {...tooltipStyle} />
                  <Bar dataKey="sessions" name="Sessoes" fill="#4285f4" radius={[0, 4, 4, 0]} />
